 1	export function jsonQuery(obj: any, path: string): any[] {
 2	  const parts = path.replace('$', '').split('.').filter(Boolean);
 3	  let current: any[] = [obj];
 4	
 5	  for (const part of parts) {
 6	    const next: any[] = [];
 7	    const arrayMatch = part.match(/^(\w+)\[(\d+|\*)]$/);
 8	
 9	    for (const item of current) {
10	      if (arrayMatch) {
11	        const [, key, index] = arrayMatch;
12	        const arr = item[key];
13	        if (Array.isArray(arr)) {
14	          if (index === '*') {
15	            // Should push all items
16	            next.push(arr);
17	          } else {
18	            next.push(arr[parseInt(index)]);
19	          }
20	        }
21	      } else {
22	        if (item && item[part] !== undefined) {
23	          next.push(item[part]);
24	        }
25	      }
26	    }
27	    current = next;
28	  }
29	  return current;
30	}
